# Compute normalized LCS ratio w.r.t max length or length of target? We'll use max(len(a), len(b)).
def normalized_lcs_ratio(a, b):
    if not a or not b:
        return 0.0
    l = lcs_len(a, b)
    return l / max(len(a), len(b))

